import {
  booleanAttribute,
  ChangeDetectionStrategy,
  Component,
  computed,
  input,
  model,
  numberAttribute,
  output,
  TemplateRef,
  ViewEncapsulation,
} from '@angular/core';
import { NgTemplateOutlet } from '@angular/common';
import { NgIcon, provideIcons } from '@ng-icons/core';
import { phosphorCaretLeft, phosphorCaretRight } from '@ng-icons/phosphor-icons/regular';

import { cn, type ClassValue } from '{{alias}}/utils';
import { sidebarBodyClass, sidebarClass, sidebarTriggerClass } from './layout.variants';

@Component({
  selector: 'hb-layout-sidebar',
  imports: [NgIcon, NgTemplateOutlet],
  viewProviders: [provideIcons({ phosphorCaretLeft, phosphorCaretRight })],
  template: `
    <div [class]="bodyClass" data-slot="layout-sidebar-body"><ng-content /></div>

    @if (hbCollapsible()) {
      <button
        type="button"
        [class]="triggerClass"
        data-slot="layout-sidebar-trigger"
        [attr.aria-expanded]="!hbCollapsed()"
        aria-label="Toggle sidebar"
        (click)="toggle()"
      >
        @if (hbTrigger(); as tpl) {
          <ng-container [ngTemplateOutlet]="tpl" />
        } @else {
          <ng-icon [name]="arrowIcon()" />
        }
      </button>
    }
  `,
  changeDetection: ChangeDetectionStrategy.OnPush,
  encapsulation: ViewEncapsulation.None,
  host: {
    '[class]': 'classes()',
    '[style.width]': 'widthStyle()',
    '[attr.data-slot]': "'layout-sidebar'",
    '[attr.data-collapsed]': 'hbCollapsed() || null',
  },
  exportAs: 'hbLayoutSidebar',
})
export class HbLayoutSidebarComponent {
  readonly hbWidth = input<string | number>(200);
  readonly hbCollapsedWidth = input(64, { transform: numberAttribute });
  readonly hbCollapsible = input(false, { transform: booleanAttribute });
  readonly hbCollapsed = model(false);
  readonly hbReverseArrow = input(false, { transform: booleanAttribute });
  readonly hbTrigger = input<TemplateRef<void> | null>(null);
  readonly class = input<ClassValue>('');

  readonly hbOnCollapsedChange = output<boolean>();

  protected readonly bodyClass = sidebarBodyClass;
  protected readonly triggerClass = sidebarTriggerClass;

  protected readonly classes = computed(() => cn(sidebarClass, this.class()));
  protected readonly widthStyle = computed(() => {
    if (this.hbCollapsed()) return `${this.hbCollapsedWidth()}px`;
    const width = this.hbWidth();
    return typeof width === 'number' ? `${width}px` : width;
  });
  protected readonly arrowIcon = computed(() => {
    const pointsLeft = this.hbReverseArrow() ? this.hbCollapsed() : !this.hbCollapsed();
    return pointsLeft ? 'phosphorCaretLeft' : 'phosphorCaretRight';
  });

  toggle(): void {
    const value = !this.hbCollapsed();
    this.hbCollapsed.set(value);
    this.hbOnCollapsedChange.emit(value);
  }
}

import {
  ChangeDetectionStrategy,
  Component,
  computed,
  contentChildren,
  input,
  ViewEncapsulation,
} from '@angular/core';

import { cn, type ClassValue } from '{{alias}}/utils';
import { HbLayoutSidebarComponent } from './layout-sidebar.component';
import { layoutClass, type HbLayoutDirection } from './layout.variants';

@Component({
  selector: 'hb-layout',
  template: `<ng-content />`,
  changeDetection: ChangeDetectionStrategy.OnPush,
  encapsulation: ViewEncapsulation.None,
  host: {
    '[class]': 'classes()',
    '[attr.data-slot]': "'layout'",
    '[attr.data-direction]': 'direction()',
  },
  exportAs: 'hbLayout',
})
export class HbLayoutComponent {
  readonly hbDirection = input<HbLayoutDirection>('auto');
  readonly class = input<ClassValue>('');

  private readonly sidebars = contentChildren(HbLayoutSidebarComponent);

  protected readonly direction = computed<'horizontal' | 'vertical'>(() => {
    const dir = this.hbDirection();
    if (dir !== 'auto') return dir;
    return this.sidebars().length > 0 ? 'horizontal' : 'vertical';
  });

  protected readonly classes = computed(() =>
    cn(layoutClass, this.direction() === 'horizontal' ? 'flex-row' : 'flex-col', this.class()),
  );
}

import { HbContentComponent } from './layout-content.component';
import { HbFooterComponent } from './layout-footer.component';
import { HbHeaderComponent } from './layout-header.component';
import { HbLayoutSidebarGroupComponent } from './layout-sidebar-group.component';
import { HbLayoutSidebarGroupLabelComponent } from './layout-sidebar-group-label.component';
import { HbLayoutSidebarComponent } from './layout-sidebar.component';
import { HbLayoutComponent } from './layout.component';

export const HbLayoutImports = [
  HbLayoutComponent,
  HbHeaderComponent,
  HbFooterComponent,
  HbContentComponent,
  HbLayoutSidebarComponent,
  HbLayoutSidebarGroupComponent,
  HbLayoutSidebarGroupLabelComponent,
] as const;

export type HbLayoutDirection = 'horizontal' | 'vertical' | 'auto';

export const layoutClass = 'flex min-h-0 w-full';
export const headerClass =
  'flex shrink-0 items-center gap-2 border-b border-border bg-card px-4 text-card-foreground';
export const footerClass =
  'flex shrink-0 items-center gap-2 border-t border-border bg-card px-4 text-sm text-muted-foreground';
export const contentClass = 'flex min-h-0 min-w-0 flex-1 flex-col overflow-auto bg-background p-4';

export const sidebarClass =
  'relative flex shrink-0 flex-col overflow-hidden border-r border-border bg-card text-card-foreground transition-[width] duration-200 ease-out';
export const sidebarBodyClass = 'flex min-h-0 flex-1 flex-col gap-2 overflow-auto p-2';
export const sidebarTriggerClass =
  'flex h-10 shrink-0 items-center justify-center border-t border-border text-muted-foreground transition-colors hover:bg-accent hover:text-accent-foreground';

export const layoutSidebarGroupClass = 'flex flex-col gap-1 py-1';
export const layoutSidebarGroupLabelClass =
  'px-2 py-1 font-mono text-[11px] font-medium uppercase tracking-[0.08em] text-muted-foreground';
